import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { loginUser, registerUser } from "../api/authapi";
import logo from "../components/assets/logo.png";

const Login = () => {
  const { login } = useAuth();
  const navigate = useNavigate();

  /* ───────── STATE ───────── */

  const [mode, setMode] = useState("login");
  const [form, setForm] = useState({
    fullName: "",
    email: "",
    contactNo: "",
    username: "",
    password: "",
    confirmPassword: "",
  });

  const [errors, setErrors] = useState({});
  const [serverError, setServerError] = useState("");
  const [successMsg, setSuccessMsg] = useState("");
  const [loading, setLoading] = useState(false);

  /* ───────── HANDLERS ───────── */

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
    setServerError("");
    setSuccessMsg("");
  };

  const validate = () => {
    const errs = {};
    if (!form.username.trim()) errs.username = "Username is required";
    if (!form.password) errs.password = "Password is required";

    if (mode === "register") {
      if (!form.fullName.trim()) errs.fullName = "Full name is required";
      if (!form.email.trim()) errs.email = "Email is required";
      else if (!/\S+@\S+\.\S+/.test(form.email))
        errs.email = "Invalid email";
      if (form.password.length < 6)
        errs.password = "Min 6 characters";
      if (!form.confirmPassword)
        errs.confirmPassword = "Please confirm password";
      else if (form.password !== form.confirmPassword)
        errs.confirmPassword = "Passwords do not match";
    }
    return errs;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }

    setLoading(true);

    try {
      /* ───── LOGIN ───── */
      if (mode === "login") {
        const res = await loginUser({
          username: form.username,
          password: form.password,
        });

        if (res?.accessToken && res?.refreshToken) {
          // ✅ Store tokens
          localStorage.setItem("sb_access_token", res.accessToken);
          localStorage.setItem("sb_refresh_token", res.refreshToken);
          localStorage.setItem("sb_userId", res.userId);
          localStorage.setItem("sb_username", res.username);

          login(res.accessToken, res.username);

          setSuccessMsg("Login successful!");
          setServerError("");

          setTimeout(() => navigate("/connection"), 1000);
        } else {
          setServerError("Invalid login response");
        }
      }

      /* ───── REGISTER ───── */
      else {
        const res = await registerUser({
          username: form.username,
          email: form.email,
          fullName: form.fullName,
          contactNo: form.contactNo,
          password: form.password,
        });

        if (res?.message) {
          setMode("login");
          setForm({
            fullName: "",
            email: "",
            contactNo: "",
            username: form.username,
            password: "",
            confirmPassword: "",
          });

          setSuccessMsg("Registered successfully! Please log in.");
        }
      }
    } catch (err) {
      setServerError(
        err.response?.data?.message || "Something went wrong"
      );
    } finally {
      setLoading(false);
    }
  };

  /* ───────── UI ───────── */

  return (
    <div className="sb-login-wrapper d-flex align-items-center justify-content-center">
      <div className="sb-login-card card shadow-lg border-0">
        <div className="card-body p-3 p-md-4">

          <div className="text-center mb-4">
            <img src={logo} alt="logo" height={50} className="mb-3" />
            <h4>{mode === "login" ? "Welcome Back" : "Create Account"}</h4>
            <p className="text-muted small">
              {mode === "login"
                ? "Sign in to SenseBoard"
                : "Register to get started"}
            </p>
          </div>

          {successMsg && (
            <div className="alert alert-success py-2 small">
              {successMsg}
            </div>
          )}

          {serverError && (
            <div className="alert alert-danger py-2 small">
              {serverError}
            </div>
          )}

          <form onSubmit={handleSubmit} noValidate>

            {mode === "register" && (
              <>
                <input
                  name="fullName"
                  placeholder="Full Name"
                  className="form-control mb-2"
                  value={form.fullName}
                  onChange={handleChange}
                />
                <input
                  name="email"
                  placeholder="Email"
                  className="form-control mb-2"
                  value={form.email}
                  onChange={handleChange}
                />
                <input
                  name="contactNo"
                  placeholder="Contact No"
                  className="form-control mb-2"
                  value={form.contactNo}
                  onChange={handleChange}
                />
              </>
            )}

            <input
              name="username"
              placeholder="Username"
              className="form-control mb-2"
              value={form.username}
              onChange={handleChange}
            />

            <input
              type="password"
              name="password"
              placeholder="Password"
              className="form-control mb-2"
              value={form.password}
              onChange={handleChange}
            />

            {mode === "register" && (
              <input
                type="password"
                name="confirmPassword"
                placeholder="Confirm Password"
                className="form-control mb-2"
                value={form.confirmPassword}
                onChange={handleChange}
              />
            )}

            <button
              type="submit"
              className="btn sb-primary-btn w-100 mt-2"
              disabled={loading}
            >
              {loading ? "Please wait..." : mode === "login" ? "Sign In" : "Register"}
            </button>
          </form>

          <div className="text-center mt-3">
            {mode === "login" ? (
              <button
                className="btn btn-link"
                onClick={() => setMode("register")}
              >
                Register here
              </button>
            ) : (
              <button
                className="btn btn-link"
                onClick={() => setMode("login")}
              >
                Sign in
              </button>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

export default Login;
